const items = $input.all();
const syncPendingRes = items[0]?.json;
const syncFailedRes = items[1]?.json;
const imagePendingRes = items[2]?.json;
const imageFailedRes = items[3]?.json;

const syncPending = syncPendingRes?.data?.content || [];
const syncFailed = syncFailedRes?.data?.content || [];
const imagePending = imagePendingRes?.data?.content || [];
const imageFailed = imageFailedRes?.data?.content || [];

const now = new Date();
const STALE_THRESHOLD_MINUTES = 60; // 1시간 이상 대기 시 경고

// 오래된 PENDING 항목 필터링
function getStaleItems(items) {
  return items.filter(item => {
    const createdAt = new Date(item.createdAt);
    const diffMinutes = (now - createdAt) / (1000 * 60);
    return diffMinutes >= STALE_THRESHOLD_MINUTES;
  });
}

const staleSyncPending = getStaleItems(syncPending);
const staleImagePending = getStaleItems(imagePending);

// 알림 조건
const alerts = [];

// 동기화 지연 알림
if (syncPending.length >= 100) {
  alerts.push({
    type: 'CRITICAL',
    category: 'sync',
    metric: 'sync_pending_count',
    value: syncPending.length,
    message: `🚨 동기화 대기 상품 ${syncPending.length}개! 마켓플레이스 API 장애 의심`
  });
} else if (syncPending.length >= 50) {
  alerts.push({
    type: 'WARNING',
    category: 'sync',
    metric: 'sync_pending_count',
    value: syncPending.length,
    message: `⚠️ 동기화 대기 상품 ${syncPending.length}개 적체 중`
  });
}

if (staleSyncPending.length >= 20) {
  alerts.push({
    type: 'CRITICAL',
    category: 'sync',
    metric: 'stale_sync_pending',
    value: staleSyncPending.length,
    message: `🚨 ${staleSyncPending.length}개 상품이 ${STALE_THRESHOLD_MINUTES}분 이상 동기화 대기 중!`
  });
}

if (syncFailed.length >= 20) {
  alerts.push({
    type: 'CRITICAL',
    category: 'sync',
    metric: 'sync_failed_count',
    value: syncFailed.length,
    message: `🚨 동기화 실패 상품 ${syncFailed.length}개! 즉시 확인 필요`
  });
} else if (syncFailed.length >= 5) {
  alerts.push({
    type: 'WARNING',
    category: 'sync',
    metric: 'sync_failed_count',
    value: syncFailed.length,
    message: `⚠️ 동기화 실패 상품 ${syncFailed.length}개`
  });
}

// 이미지 업로드 지연 알림
if (imagePending.length >= 200) {
  alerts.push({
    type: 'CRITICAL',
    category: 'image',
    metric: 'image_pending_count',
    value: imagePending.length,
    message: `🚨 이미지 업로드 대기 ${imagePending.length}개! Fileflow 장애 의심`
  });
} else if (imagePending.length >= 100) {
  alerts.push({
    type: 'WARNING',
    category: 'image',
    metric: 'image_pending_count',
    value: imagePending.length,
    message: `⚠️ 이미지 업로드 대기 ${imagePending.length}개 적체 중`
  });
}

if (staleImagePending.length >= 50) {
  alerts.push({
    type: 'CRITICAL',
    category: 'image',
    metric: 'stale_image_pending',
    value: staleImagePending.length,
    message: `🚨 ${staleImagePending.length}개 이미지가 ${STALE_THRESHOLD_MINUTES}분 이상 업로드 대기 중!`
  });
}

if (imageFailed.length >= 30) {
  alerts.push({
    type: 'CRITICAL',
    category: 'image',
    metric: 'image_failed_count',
    value: imageFailed.length,
    message: `🚨 이미지 업로드 실패 ${imageFailed.length}개! S3/Fileflow 확인 필요`
  });
} else if (imageFailed.length >= 10) {
  alerts.push({
    type: 'WARNING',
    category: 'image',
    metric: 'image_failed_count',
    value: imageFailed.length,
    message: `⚠️ 이미지 업로드 실패 ${imageFailed.length}개`
  });
}

return {
  timestamp: now.toISOString(),
  summary: {
    sync: {
      pending: syncPending.length,
      stalePending: staleSyncPending.length,
      failed: syncFailed.length
    },
    image: {
      pending: imagePending.length,
      stalePending: staleImagePending.length,
      failed: imageFailed.length
    },
    staleThresholdMinutes: STALE_THRESHOLD_MINUTES
  },
  alerts,
  hasAlerts: alerts.length > 0,
  hasCritical: alerts.some(a => a.type === 'CRITICAL'),
  hasSyncIssue: alerts.some(a => a.category === 'sync'),
  hasImageIssue: alerts.some(a => a.category === 'image')
};

const data = $input.first().json;
const alerts = data.alerts;
const summary = data.summary;

const hasCritical = data.hasCritical;
const emoji = hasCritical ? '🚨' : '⚠️';
const color = hasCritical ? '#ff0000' : '#ffcc00';

// 카테고리별 알림 분류
const syncAlerts = alerts.filter(a => a.category === 'sync').map(a => a.message).join('\n');
const imageAlerts = alerts.filter(a => a.category === 'image').map(a => a.message).join('\n');

let alertSections = [];

if (syncAlerts) {
  alertSections.push(`*📦 상품 동기화*\n${syncAlerts}`);
}

if (imageAlerts) {
  alertSections.push(`*🖼️ 이미지 업로드*\n${imageAlerts}`);
}

const alertText = alertSections.join('\n\n');

const slackMessage = {
  text: `${emoji} CrawlingHub Sync Delay Alert`,
  attachments: [
    {
      color: color,
      blocks: [
        {
          type: 'header',
          text: {
            type: 'plain_text',
            text: `${emoji} CrawlingHub 동기화 지연 알림`,
            emoji: true
          }
        },
        {
          type: 'section',
          text: {
            type: 'mrkdwn',
            text: alertText
          }
        },
        {
          type: 'divider'
        },
        {
          type: 'section',
          text: {
            type: 'mrkdwn',
            text: '*📦 상품 동기화 현황*'
          }
        },
        {
          type: 'section',
          fields: [
            {
              type: 'mrkdwn',
              text: `*대기 중*\n${summary.sync.pending}개`
            },
            {
              type: 'mrkdwn',
              text: `*장기 대기 (>${summary.staleThresholdMinutes}분)*\n${summary.sync.stalePending}개`
            },
            {
              type: 'mrkdwn',
              text: `*실패*\n${summary.sync.failed}개`
            }
          ]
        },
        {
          type: 'section',
          text: {
            type: 'mrkdwn',
            text: '*🖼️ 이미지 업로드 현황*'
          }
        },
        {
          type: 'section',
          fields: [
            {
              type: 'mrkdwn',
              text: `*대기 중*\n${summary.image.pending}개`
            },
            {
              type: 'mrkdwn',
              text: `*장기 대기 (>${summary.staleThresholdMinutes}분)*\n${summary.image.stalePending}개`
            },
            {
              type: 'mrkdwn',
              text: `*실패*\n${summary.image.failed}개`
            }
          ]
        },
        {
          type: 'context',
          elements: [
            {
              type: 'mrkdwn',
              text: `⏰ ${data.timestamp}`
            }
          ]
        }
      ]
    }
  ]
};

return { slackMessage, hasCritical, hasSyncIssue: data.hasSyncIssue, hasImageIssue: data.hasImageIssue };
